UPDATE course_contents
SET week_plan = $week_data$[{"week":1,"theme":"成为观察家","days_range":"1-7","goals":["激发兴趣，建立科学观察的基本概念，并制作完成核心研究工具——《第六感日记》。成功记录至少三次“主人回家”事件。"],"activities":[{"sequence":1,"day_label":"Day 1","day_range":"1","title_zh":"项目启动：杰提的神秘故事","title_en":"Project Kick-off: The Mystery of Jaytee","duration":"约30分钟","content":"(任务时长：约30分钟)\n欢迎加入“伊卡洛斯计划”的第一个任务！从今天起，你将成为一名“宠物侦探”。你的任务，是去发现一个隐藏在我们毛茸茸、黏乎乎或者有羽毛的朋友身上的大秘密！\n在我们开始之前，请先阅读一个真实的故事。这是一个关于一只名叫“杰提”（Jaytee）的小狗的传奇故事。\n在一个叫做英格兰的地方，有一位女士叫帕姆（Pam），她有一只非常可爱的狗狗，名叫杰提。帕姆发现了一件很奇怪的事：每次她要下班回家的时候，不管她离家有多远，也不管她是不是准时回家，杰提好像总能提前知道！\n杰提会在帕姆回家的确切时间前几分钟，就跑到窗户边，安静地坐下，眼睛望着窗外，好像在说：“我的主人就要回来啦！”\n帕姆觉得这太神奇了！她想：“杰提是怎么知道的呢？它听不到我的车声，因为我还离得很远。它也闻不到我的气味。难道……它有心灵感应？”\n为了解开这个谜团，一位名叫鲁珀特·谢尔德雷克（Rupert Sheldrake）的科学家决定帮助帕姆。他们在家安装了一台摄像机，专门对着杰提最喜欢等待的窗户。\n他们做了很多很多次实验。有时候，帕姆会坐朋友的车回家，这样就没有熟悉的车声了。有时候，她会比平时早很多或者晚很多回家。但每一次，摄像机都清楚地拍到：就在帕姆心里想着“好了，我要回家了”并开始行动后不久，杰提就跑到了窗户边，开始它那充满期待的等待。\n科学家们分析了数百小时的录像带，发现杰提的“预知能力”不是巧合。它好像真的能“感觉”到主人回家的念头！\n杰提的故事告诉我们，也许动物和我们之间，有一条看不见的、充满爱的“纽带”。这个秘密，至今还没有被完全解开。\n现在，轮到你了，小侦探。你的宠物，是不是也有像杰提一样的“第六感”呢？让我们一起去发现吧！\n仔细阅读《杰提的神秘故事》。\n思考一下：你觉得杰提是怎么知道主人要回家的？有没有可能它只是在猜？\n接受任务： 在下方的文本框中，输入你和你宠物的名字。告诉我们你准备和哪位动物伙伴一起完成这次伟大的探险！\n格式： “侦探 [你的名字] 和我的伙伴 [宠物的名字] 接受任务！”\n上传伙伴的照片： 点击“上传图片”按钮，分享一张你和你的宠物伙伴最棒的合影，或者它自己的萌照。让我们都认识一下这位未来的“研究对象”！"},{"sequence":2,"day_label":"Day 2-4","day_range":"2-4","title_zh":"任务准备：制作你的《第六感日记》","title_en":"Mission Prep: Crafting Your 'Sixth Sense Diary'","duration":"约45分钟，可在3天内完成","content":"(任务时长：约45分钟，可在3天内完成)\n每一位出色的侦探都需要一个工具来记录线索。在接下来的任务中，你的主要工具就是一本特制的日记——《第六感日记》。它将帮助你捕捉到宠物每一个微小的、可疑的“超能力”瞬间！\n你可以选择两种方式来制作你的日记：\n选项A：纸笔侦探日记（推荐！）\n亲手制作的感觉最棒了！\n准备材料： 一个笔记本、彩笔、尺子。\n设计封面： 在笔记本的封面上，画上你的宠物，写上《[宠物名字]的第六感日记》，还可以画上放大镜、脚印等侦探元素。\n制作记录页： 在日记的内页，用尺子和笔画出下面的表格。你可以请爸爸妈妈帮忙。多画几页备用哦！\n（这是一个你可以打印或照着画的模板）\n第六感日记 - 第 [ ] 次记录\n \n日期\n（例如：2025年11月15日）\n回家的家人\n（例如：妈妈）\n家人回家的交通工具\n（例如：开车 / 走路 / 坐公交车）\n我猜家人什么时候到家\n（例如：下午6:00）\n我的宠物从什么时候开始等待？\n（例如：下午5:50）\n它在做什么？（请画下来或写下来）\n（在这里画画或写字，例如：坐在门口，尾巴小幅度摇摆，耳朵竖起来）\n家人实际到家的时间\n（例如：下午6:05）\n我的宠物“猜”对了吗？\n是 / 差不多 / 不是 (请圈出你的答案)\n选项B：数字侦探日记\n如果你更喜欢在电脑或平板上操作，也可以创建一个数字文件夹。\n创建文件夹： 在你的设备上创建一个名为“宠物侦探日记”的文件夹。\n创建文档： 在文件夹里，每次记录都创建一个新的文本文档，并按照上面的表格格式，把每一项内容都打字记录下来。你还可以在文档里插入宠物的照片或视频。\n理解日记中每一项的意义。为什么记录“交通工具”很重要？（提示：这可以帮助我们排除“听到熟悉车声”的可能性）。为什么“画下来”很重要？（提示：图画比文字更能捕捉宠物的姿态和情绪）。\n选择一种你喜欢的方式，动手制作你的日记本。\n展示你的工具：\n如果你制作了纸质日记，请拍一张你精美封面的照片，以及一张画好表格的内页照片，然后上传。\n如果你制作了数字日记，请截一张你的文件夹和第一个空白文档的图片，然后上传。"},{"sequence":5,"day_label":"Day 5-7","day_range":"5-7","title_zh":"开始调查：记录前三次回家事件","title_en":"The Investigation Begins: First Three Entries","duration":"每天约15分钟观察，可在3天内完成","content":"(任务时长：每天约15分钟观察，可在3天内完成)\n你的工具已经准备就绪，现在是时候开始真正的调查了！在接下来的三天里，你的任务是：至少完成三份完整的《第六感日记》记录。\n选择对象： 选择一位每天都会出门回家的家人作为你的主要观察对象，比如爸爸或妈妈。\n获取情报： 在家人出门时，可以悄悄问一下他们大概什么时候回家。把这个时间记录在你的“我猜家人什么时候到家”一栏。\n保持警惕： 在家人预计回家时间的前15-20分钟，就要开始密切关注你的宠物了！你需要像一个真正的侦探一样，不放过任何蛛丝马迹。\n它是不是突然从睡梦中醒来？\n它是不是停止玩玩具，开始在房间里踱步？\n它是不是跑到门口或者窗边坐下？\n它的耳朵、尾巴、姿势有没有什么特别的变化？\n精确记录： 一旦你发现宠物开始出现“等待行为”，立刻记下时间！然后详细地在“它在做什么？”一栏里画下来或写下来。\n核对事实： 当家人真的回到家时，记下“实际到家的时间”。\n初步结论： 对比宠物开始等待的时间和家人实际到家的时间，判断你的宠物这次是不是“猜”对了，并圈出你的答案。\n学习如何进行不打扰的观察。作为一个侦探，我们不能让“嫌疑人”（我们的宠物）知道我们在观察它，否则它可能会因为我们的关注而改变行为。\n练习用图画或生动的文字来描述动物的行为。\n提交你的调查报告：\n请将你完成的三份日记记录提交上来。\n你可以选择在下方的文本框中，按照日记表格的格式，打字输入这三次记录的全部内容。\n或者，你也可以用手机或相机拍摄你手写日记的三张清晰照片，然后一次性上传这三张图片。\n恭喜你，小侦探！你已经完成了第一周的任务，收集到了宝贵的第一手资料。下周，我们将学习如何采访“证人”，并让你的数据“开口说话”！敬请期待！"}]},{"week":2,"theme":"采访证人与数据魔法","days_range":"8-14","goals":["学习侦探的另一项重要技能——采访“证人”（家人），以收集更多维度的信息。同时，学习将零散的“线索”（日记记录）通过盖亚的“数据魔法”变成直观的图表，初步分析宠物的“超能力”模式。"],"activities":[{"sequence":8,"day_label":"Day 8-10","day_range":"8-10","title_zh":"侦探技巧：学习如何采访“证人”","title_en":"Detective Skill: How to Interview a Witness","duration":"约60分钟，可在3天内完成","content":"(任务时长：约60分钟，可在3天内完成)\n你好，小侦探！上周你做得非常棒，通过秘密观察，我们已经收集到了一些关于宠物“第六感”的宝贵线索。但是，一个优秀的侦探不仅要会观察，更要会提问！\n我们每天回家的家人，就是这个神秘事件中最重要的“证人”。通过采访他们，我们可以了解到一些我们看不到的信息，比如他们是什么时候“决定”回家的？路上有没有在想念宠物？这些都可能是解开谜团的关键！\n在开始之前，盖亚为你准备了几个采访小技巧：\n礼貌第一： 找到一个家人不忙的时候，礼貌地问：“你好，我可以采访你几分钟吗？这是我的侦探任务。”\n准备问题： 提前想好你要问的问题，这样会显得你非常专业！\n认真倾听： 用你的《第六感日记》把家人的回答记录下来。\n表示感谢： 采访结束后，一定要说：“谢谢你接受我的采访！”\n你可以把这些问题抄在你的日记本里，采访的时候用。\n问题1： “（称呼），请问你今天大概是什么时候决定要下班/放学回家的？”（提示：这个问题很重要！我们想知道是“心里的决定”重要，还是“走出大门”这个动作重要。）\n问题2： “你今天回家的路上，有没有想起过我们家的 [宠物名字] 呀？如果有，大概是什么时候，在想什么呢？”\n问题3： “你今天回家路上有没有发生什么特别的事情？比如堵车了，或者绕路去买了东西？”（提示：这可以帮助我们了解为什么家人回家的时间会变化。）\n阅读并理解“盖亚的采访小课堂”和“采访问题模板”。\n思考一下，为什么我们要问家人“心里在想什么”，而不仅仅是问他们“几点到家的”？\n提交你的采访记录：\n请对你上周主要观察的那位家人进行一次正式的采访。\n将你的采访问题和家人的回答，清清楚楚地记录在你的《第六感日记》中。\n提交方式（二选一）：\n拍照上传： 拍摄你手写的采访记录页，确保照片清晰。\n文字提交： 在下方的文本框中，打字输入你的采访记录。\n格式：\n采访对象：妈妈\n问题1的回答：……\n问题2的回答：……\n问题3的回答：……"},{"sequence":11,"day_label":"Day 11-12","day_range":"11-12","title_zh":"数据魔法：让你的线索“开口说话”","title_en":"Data Magic: Making Your Clues Speak","duration":"约30分钟，可在2天内完成","content":"(任务时长：约30分钟，可在2天内完成)\n小侦探，到目前为止，你的日记里已经有了好几条零散的线索。单独看，它们可能只是一个个小故事。但是，当我们把它们放在一起时，就可能会发现一个惊人的模式！\n现在，欢迎来到盖亚的“数据魔法实验室”。在这里，我们要把你记录的文字，变成一张会说话的图片！\n整理你的所有记录： 拿出你的《第六感日记》，把你从第一周到现在完成的所有记录（至少3-5次）都放在面前。\n呼叫盖亚的数据魔法： 在下面的区域，你会看到一个简单的表格。请根据你的每一份日记，依次输入结果。\n【宠物第六感数据输入站】\n第一次记录： 我的宠物“猜”对了吗？ ( ) 是 ( ) 差不多 ( ) 不是\n第二次记录： 我的宠物“猜”对了吗？ ( ) 是 ( ) 差不多 ( ) 不是\n第三次记录： 我的宠物“猜”对了吗？ ( ) 是 ( ) 差不多 ( ) 不是\n第四次记录： 我的宠物“猜”对了吗？ ( ) 是 ( ) 差不多 ( ) 不是\n（……你可以继续添加更多记录）\n[点击这里，施展数据魔法！]\n见证奇迹： 当你点击按钮后，盖亚会立刻为你生成一张“宠物第六感模式图”。这张图会非常清楚地告诉你，在你的所有观察中：\n有多少次宠物完全猜对了（用一排绿色的爪印  表示）。\n有多少次宠物差不多猜对了（用一排黄色的爪印  表示）。\n有多少次宠物完全没猜对（用一排灰色的爪印  表示）。\n学习如何从图表中读取信息。看看你的“模式图”，哪一排的爪印最长？\n初步思考：根据这张图，你觉得你的宠物有“第六感”吗？为什么？记住，这只是初步结论，我们的调查才刚刚开始！\n分享你的模式图：\n请将盖亚为你生成的“宠物第六感模式图”截图并上传。\n写下你的初步分析：\n在下方的文本框中，用一两句话描述你从图表中看到了什么。\n格式： “我的模式图显示，在 [ ] 次记录中，有 [ ] 次是绿色的，[ ] 次是黄色的，[ ] 次是灰色的。我认为……”"},{"sequence":13,"day_label":"Day 13-14","day_range":"13-14","title_zh":"继续调查：积累更多的证据！","title_en":"Keep Investigating: Gather More Evidence!","duration":"每天约15分钟观察","content":"(任务时长：每天约15分钟观察)\n小侦探，你做得太棒了！你已经学会了观察、采访和初步的数据分析。但科学和侦探工作一样，最重要的就是证据！证据越多，我们的结论就越可靠。\n在本周的最后两天，请你继续保持警惕，完成至少两份新的《第六感日记》记录。\n回顾你之前的所有记录，看看有没有什么有趣的发现。是不是某位家人回家时，宠物的反应特别准？是不是某种交通工具回家时，宠物更容易“猜”到？\n提交最新的调查报告：\n请将你在这两天完成的两份新日记记录提交上来。\n提交方式（二选一）：\n拍照上传： 拍摄你手写日记的两张清晰照片。\n文字提交： 在下方的文本框中，打字输入这两次记录的全部内容。\n非常出色，小侦探！第二周的任务完成了。你不仅是一个观察家，现在更是一位懂得采访和数据分析的“专业人士”了！你的证据库正在变得越来越丰富。下周，我们将进入一个更激动人心的阶段——我们要主动设计一个“心灵感应”游戏，从被动观察，变成主动测试！准备好迎接挑战了吗？"}]},{"week":3,"theme":"设计你的心灵游戏","days_range":"15-21","goals":["完成从“被动观察家”到“主动实验设计师”的身份转变。设计并执行一个简单的、非语言的“心灵游戏”，尝试主动用“意念”与宠物沟通，并严谨地记录实验过程与结果。"],"activities":[{"sequence":15,"day_label":"Day 15-16","day_range":"15-16","title_zh":"实验设计课：从观察到提问","title_en":"Experiment Design Class: From Observing to Asking","duration":"约45分钟，可在2天内完成","content":"(任务时长：约45分钟，可在2天内完成)\n你好，小侦探！过去两周，我们像影子一样悄悄地观察和记录，收集了很多关于宠物“第六感”的线索。我们观察的是“宠物能不能猜到我们回家”。\n现在，我们要升级挑战了！一个更厉害的侦探，不仅会等待线索出现，更会主动设计一个“陷阱”或“谜题”，来测试“嫌疑人”的反应。\n我们的新问题是：“我们能不能用‘心里想’的方式，让宠物去做一件它平时不会主动做的事？”\n这就是我们这周要玩的“心灵游戏”！\n在设计游戏之前，盖亚要告诉你一个成为“科学魔法师”的秘密咒语，这个咒语叫做**“排除干扰”**。\n在科学实验里，我们想知道是不是A导致了B，就必须想办法把其他可能导致B的原因都关掉。比如：\n干扰1：声音。 如果你一边在心里想，一边嘴里发出声音，那宠物可能是听到了声音，而不是“感觉”到你的想法。\n干扰2：气味。 如果你拿着零食在心里想，宠物可能是闻到了香味。\n干扰3：视线。 如果你一直盯着宠物看，它可能是感觉到了你的注视（这也是一种超能力哦！我们以后会研究！）。\n所以，我们设计的游戏，必须想办法“排除”掉这些干扰。\n这是一个经典的心灵感应游戏，让我们一起来完善它。\n游戏目标： 用意念“召唤”你的宠物来吃一个它看不见的零食。\n游戏步骤：\n准备阶段： 选择一个宠物最爱的小零食。\n设置场景： 在一个房间（比如客厅）的地板中间，放一个小盘子，把零食放在盘子里。确保宠物不在这个房间里。\n进入“发送”位置： 你自己去另一个房间（比如你的卧室），关上门，确保宠物看不到你，也听不到你轻微的动作声。\n开始“发送”意念： 设定一个闹钟（比如5分钟后响）。在这5分钟里，你闭上眼睛，非常非常专注地在脑海里想象你的宠物，想象它走进客厅，找到盘子，开心地吃掉零食的整个画面。你可以在心里默念它的名字，对它说：“[宠物名字]，快来客厅吃好吃的呀！” 记住：千万不要发出任何声音！\n观察结果： 5分钟闹钟响后，立刻去客厅检查。零食还在吗？你的宠物在客厅吗？\n记录： 把整个过程和结果，详细地记录在你的《心灵游戏实验记录表》上。\n仔细阅读“心灵游戏设计方案A”的每一个步骤。\n思考：这个设计方案排除了哪些“干扰”？还有没有哪些可能的干扰我们没有考虑到？\n在你的《第六感日记》本里，新开一页，画出《心灵游戏实验记录表》。模板如下：\n心灵游戏实验记录表 - 第 [ ] 次\n \n实验日期和时间\n \n我的“意念”目标\n（例如：让狗狗来客厅吃掉盘子里的饼干）\n实验地点（“发送”意念的房间）\n（例如：我的卧室）\n零食地点\n（例如：客厅中央的蓝色小盘子里）\n实验开始前，宠物在哪里/在做什么？\n（例如：在阳台睡觉）\n“意念发送”时长\n（例如：5分钟）\n实验结果（请详细描述！）\n（例如：5分钟后，我发现饼干不见了！狗狗正在舔嘴巴。或者：饼干还在，狗狗还在阳台睡觉。）\n我的分析（这次成功了吗？为什么？）\n \n提交你的实验记录表：\n请拍照上传你亲手绘制的、空白的《心灵游戏实验记录表》。我们要确保每一位侦探的工具都准备无误！"},{"sequence":17,"day_label":"Day 17-20","day_range":"17-20","title_zh":"执行与记录：进行三次心灵游戏","title_en":"Execution & Recording: Three Rounds of the Mind Game","duration":"每天约20分钟，可在4天内完成","content":"(任务时长：每天约20分钟，可在4天内完成)\n小侦探，现在是展示你“超能力”的时刻了！在本周接下来的时间里，你需要进行至少三次“心灵游戏”实验。\n选择最佳时机： 最好选择家里比较安静，宠物也比较放松的时候进行实验。不要在它刚吃饱或者非常想出去玩的时候做。\n保持一致性： 尽量每次实验的条件都差不多。比如，都在同一个房间“发送”意念，都用同一种零食。这会让你的实验结果更可靠。\n专注！专注！再专注！ “发送意念”环节是成功的关键。你需要像电影里的超级英雄一样，集中你所有的注意力。想象你和宠物之间有一条看不见的电话线，你正在通过这条线给它发送信息。\n诚实记录： 无论实验成功还是失败，都要诚实、详细地记录下来。在科学的世界里，失败的实验和成功的实验一样有价值，因为它告诉我们“此路不通”，可以帮助我们设计更好的实验！\n可以尝试变化： 如果你觉得“食物的召唤”太难了，也可以自己设计一个更简单的目标。比如：\n“到我身边来”： 宠物在客厅，你在卧室关上门，在意念里呼唤它来你的门口。\n“看看那个玩具”： 当宠物和你都在同一个房间，但它没在看你时，你在心里默默地想让它去看某个特定的玩具。\n亲身体验“专注”的感觉。尝试在发送意念时，排除脑海里其他的杂念。\n学习如何客观地描述实验结果，即使它和你期望的不一样。\n提交你的三次实验报告：\n请将你完成的三份《心灵游戏实验记录表》提交上来。\n提交方式（二选一）：\n拍照上传： 拍摄你手写的三张清晰的记录表照片。\n文字提交： 在下方的文本框中，一次性打字输入这三次实验的全部记录内容。确保每次记录都包含表格里的所有项目。"},{"sequence":21,"day_label":"Day 21","day_range":"21","title_zh":"本周复盘：分享你的第一次实验","title_en":"Weekly Review: Sharing Your First Experiment","duration":"约20分钟","content":"(任务时长：约20分钟)\n祝贺你，小侦探！你已经完成了第一次由自己亲手设计的科学实验！这非常了不起！\n现在，请回顾一下你这周的实验记录，并和全球的其他小侦探们分享你的一个最有趣的发现。\n学习如何从自己的实验记录中提炼出一个最想和别人分享的“亮点”。\n发布你的“侦探快报”：\n在下方的“全球侦探交流区”文本框中，用几句话分享你这周最有趣的一次实验经历。\n格式：\n我的实验标题： （例如：“一次失败但有趣的召唤”）\n我的经历： （例如：“我尝试用意念让我的猫咪‘咪咪’来吃鱼干，但它完全没理我，睡得像一头小猪。不过，当我打开卧室门的时候，它立刻就醒了，好像在说‘你是不是有好事瞒着我？’我觉得它可能知道我在做什么，但就是懒得动！”）\n太棒了，小侦探！你不仅学会了如何设计和执行实验，还学会了分享和反思。科学的进步，就是在这样一次次的尝试、失败、分享和再尝试中发生的。你已经走在了成为一名真正科学家的路上！下周，我们将迎来我们项目的最终环节——整理所有证据，制作你的最终报告，并准备在全球报告会上惊艳亮相！"}]},{"week":4,"theme":"成果展示与全球报告会","days_range":"22-28","goals":["整合前三周的所有观察日记、采访记录和实验数据，制作一份属于自己的、图文并茂的《宠物第六感观察报告》。同时，准备一个简短的演讲，在全球在线“宠物侦探报告会”上，向世界各地的同伴们分享你的发现和故事。"],"activities":[{"sequence":22,"day_label":"Day 22-24","day_range":"22-24","title_zh":"整合线索：制作你的最终报告","title_en":"Synthesizing Clues: Creating Your Final Report","duration":"约90分钟，可在3天内完成","content":"(任务时长：约90分钟，可在3天内完成)\n你好，小侦探！经过三周的辛勤工作，你的《第六感日记》里已经装满了宝贵的线索和证据。现在，是时候将这些碎片化的信息，整理成一份专业、漂亮的最终报告了！\n这份报告不仅是你这次探险的总结，更是你送给你和宠物伙伴的一份珍贵礼物。\n别担心，盖亚会一步步指导你完成这份报告。你的《宠物第六感观察报告》应该包含以下几个部分：\n第一部分：我的伙伴档案 (My Partner's Profile)\n内容： 放上你伙伴最帅/最萌的照片，写上它的名字、品种、年龄，以及你最喜欢它的三个地方。\n第二部分：观察发现 (Observation Findings)\n内容：\n把你之前由盖亚生成的“宠物第六感模式图”（爪印图）贴在这里。\n根据这张图，写下你的结论。例如：“在我总共 [ ] 次的观察中，我的宠物 [ ] 次准确地预知了家人回家，这说明它可能真的有第六感！” 或者，“我的宠物大多数时候都没有猜对，我觉得它可能只是喜欢在门口待着。”\n第三部分：心灵游戏实验 (The Mind Game Experiment)\n内容：\n选择你印象最深刻的一次“心灵游戏”实验，把当时的记录表内容抄写或粘贴过来。\n写下你对这次实验的感想。你觉得“心灵感应”真的发生了吗？如果没有，你认为可能是什么原因？\n第四部分：我的侦探心得 (My Detective Reflections)\n内容： 这是最重要的部分！请回答以下两个问题：\n通过这次“宠物侦探”任务，你对你的宠物有了什么新的认识？\n你认为人类和动物之间，除了喂食和玩耍，还有没有其他更深的连接方式？\n学习如何将不同类型的信息（图片、图表、文字）组织在一起，形成一份结构清晰的报告。\n学习如何表达自己的观点和感想，而不仅仅是陈述事实。\n提交你的最终报告草稿：\n你可以用纸笔和彩笔，在一张或几张大纸上完成你的报告，然后拍照上传。\n你也可以使用电脑上的Word、PPT或任何你喜欢的软件来制作一份电子报告，然后上传文件或截图。\n请确保报告包含了上面提到的所有四个部分。 这是一份草稿，不需要非常完美，但内容要完整。盖亚和项目导师会给你一些反馈和建议。"},{"sequence":25,"day_label":"Day 25-26","day_range":"25-26","title_zh":"演讲练习：准备你的3分钟分享","title_en":"Presentation Practice: Preparing Your 3-Minute Share","duration":"约45分钟，可在2天内完成","content":"(任务时长：约45分钟，可在2天内完成)\n小侦探，在本周末，我们将举行一场盛大的“全球宠物侦探报告会”！届时，你将有机会把你过去一个月的发现，分享给来自不同国家的小伙伴们。\n每个人的分享时间是3分钟。你需要在这短短的时间里，精彩地讲述你的探险故事。\n别紧张，成为一个出色的演讲者很简单，记住三个要点：\n讲故事，而不是念稿子： 不要只是读你的报告。选择你报告里最有趣的部分，比如你的宠物最神奇的一次“预知”，或者你做“心灵游戏”时的搞笑经历，把它们变成一个吸引人的小故事。\n展示你的“王牌证据”： 准备好展示你报告里的关键图片，比如你伙伴最可爱的照片，或者那张“爪印模式图”。一张图片胜过千言万语！\n练习，练习，再练习！ 对着镜子、对着爸爸妈妈，或者对着你的宠物伙伴，多练习几次。用手机录下来看看，你会发现自己可以做得更好！\n第1分钟： 大家好！我是侦探 [你的名字]，这是我的伙伴 [宠物名字]！（展示照片）。我们一起参加了“宠物侦探”任务。\n第2分钟： 在我的调查中，我发现了一个秘密！（展示你的“爪印模式图”）。在 [ ] 次观察里，它猜对了 [ ] 次！我还做了一个心灵游戏……（简单讲述一次实验经历）。\n第3分钟： 通过这次任务，我感觉我和我的宠物更亲近了。我认为……（分享你的心得）。谢谢大家！\n根据你的最终报告，撰写一份简单的3分钟演讲稿。\n对着家人或镜子进行至少两次练习。\n提交你的演讲稿：\n在下方的文本框中，打字输入你的3分钟演讲稿。\n（可选）提交你的练习录音/视频：\n如果你足够勇敢，可以上传一段你练习演讲的音频或视频。这会帮助你获得更多自信！"},{"sequence":27,"day_label":"Day 27-28","day_range":"27-28","title_zh":"终极时刻：全球报告会与项目结业","title_en":"The Final Moment: Global Conference & Graduation","duration":"报告会约60分钟","content":"(任务时长：报告会约60分钟)\nDay 27: 最后的准备\n任务： 根据收到的反馈，修改和完善你的最终报告和演讲稿。熟悉你的讲稿，确保你对要分享的内容充满信心。准备好报告会需要的设备（电脑、网络、摄像头）。\nDay 28: 全球宠物侦探报告会\n活动流程：\n准时上线： 在预定的时间，点击进入全球在线会议室。\n开场与欢迎： 盖亚和项目导师会欢迎所有来自世界各地的小侦探。\n分享环节： 按照顺序，每位小侦探将有3分钟的时间来分享自己的发现。请大胆地打开你的摄像头和麦克风！\n提问与交流： 在每几位同学分享后，会有短暂的提问和交流时间。你可以向别人提问，也可以回答别人的问题。\n颁奖与结业： 会议的最后，盖亚将为每一位完成任务的小侦探颁发一张精美的电子版**“伊卡洛斯计划 - 初级宠物侦探”**证书！\n提交你的最终版报告：\n请在报告会开始前，上传你最终完成的、最完美的《宠物第六感观察报告》。这将作为你的结业作品被永久保存在你的“伊卡洛斯计划”档案中。\n分享你的结业证书：\n报告会结束后，请将你获得的电子证书截图上传，并写下一句你的结业感言！\n亲爱的小侦探，祝贺你！你不仅出色地完成了为期四周的探险任务，更重要的是，你亲手推开了一扇通往未知世界的大门。你学会了像科学家一样观察、提问、实验和分享。记住今天的感觉，保持这份好奇心和勇气，因为整个宇宙的奥秘，都在等待着像你一样的探索者去揭开。我们下一个模块再见！"}]}]$week_data$::jsonb
WHERE system_id = '9da7c347-fe63-4c81-81e1-df576bcd2e6c'::uuid
  AND sequence_number = 1;

-- 验证更新
SELECT
  sequence_number,
  title,
  jsonb_array_length(week_plan) as weeks_count,
  (
    SELECT COUNT(*)
    FROM jsonb_array_elements(week_plan) w,
         jsonb_array_elements(w->'activities') a
  ) as activities_count
FROM course_contents
WHERE system_id = '9da7c347-fe63-4c81-81e1-df576bcd2e6c'::uuid
  AND sequence_number = 1;
